-- Supabase / PostgreSQL INSERT SQL (從本地 SQLite 匯出)
-- 在 Supabase SQL Editor 執行本腳本

-- ===== stores =====
TRUNCATE TABLE stores CASCADE;

-- ===== users =====
TRUNCATE TABLE users CASCADE;

-- ===== pets =====
TRUNCATE TABLE pets CASCADE;

-- ===== pet_status_logs =====
TRUNCATE TABLE pet_status_logs CASCADE;

-- 重設 sequences (PostgreSQL 需要)
SELECT setval('stores_id_seq', (SELECT MAX(id) FROM stores));
SELECT setval('pets_id_seq', (SELECT MAX(id) FROM pets));
SELECT setval('users_id_seq', (SELECT MAX(id) FROM users));